proof_block:
// Force the two `forall` quantifiers from `processes_unchanged`,
// `threads_unchanged_except`, `containers_(tree|owned_proc|)_unchanged(_except)`
// for run 1 and run 2 to line up by re-asserting them with explicit
// triggers and matching the trigger shape of the relational spec fns
// (`old.get_*(ptr)`).

// --- Domain equalities (immediate from ensures) ---------------------------
assert(post1_self_.container_dom() =~= pre_self_.container_dom());
assert(post2_self_.container_dom() =~= pre_self_.container_dom());
assert(post1_self_.container_dom() =~= post2_self_.container_dom());

assert(post1_self_.thread_dom() =~= pre_self_.thread_dom());
assert(post2_self_.thread_dom() =~= pre_self_.thread_dom());
assert(post1_self_.thread_dom() =~= post2_self_.thread_dom());

// `processes_unchanged` carries `old.proc_dom() =~= new.proc_dom()`.
assert(post1_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post2_self_.proc_dom() =~= pre_self_.proc_dom());
assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());

// --- processes_unchanged: pointwise get_proc equality on both runs --------
assert forall|p: ProcPtr| #![trigger pre_self_.get_proc(p)]
    pre_self_.proc_dom().contains(p) implies
        post1_self_.get_proc(p) == post2_self_.get_proc(p)
by {
    assert(post1_self_.get_proc(p) =~= pre_self_.get_proc(p));
    assert(post2_self_.get_proc(p) =~= pre_self_.get_proc(p));
}

// --- threads_unchanged_except: all threads but `thread_ptr` match pre -----
assert forall|t: ThreadPtr| #![trigger pre_self_.get_thread(t)]
    pre_self_.thread_dom().contains(t) && t != thread_ptr implies
        post1_self_.get_thread(t) == post2_self_.get_thread(t)
by {
    assert(!(set![thread_ptr]).contains(t));
    assert(post1_self_.get_thread(t) =~= pre_self_.get_thread(t));
    assert(post2_self_.get_thread(t) =~= pre_self_.get_thread(t));
}

// --- The single modified thread is updated identically in both runs -------
assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors@
    =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors@.update(edp_idx as int, None));
assert(post2_self_.get_thread(thread_ptr).endpoint_descriptors@
    =~= pre_self_.get_thread(thread_ptr).endpoint_descriptors@.update(edp_idx as int, None));
assert(post1_self_.get_thread(thread_ptr).endpoint_descriptors@
    =~= post2_self_.get_thread(thread_ptr).endpoint_descriptors@);

assert(post1_self_.get_thread(thread_ptr).blocking_endpoint_index
    == pre_self_.get_thread(thread_ptr).blocking_endpoint_index);
assert(post2_self_.get_thread(thread_ptr).blocking_endpoint_index
    == pre_self_.get_thread(thread_ptr).blocking_endpoint_index);
assert(post1_self_.get_thread(thread_ptr).blocking_endpoint_index
    == post2_self_.get_thread(thread_ptr).blocking_endpoint_index);

assert(post1_self_.get_thread(thread_ptr).state
    == pre_self_.get_thread(thread_ptr).state);
assert(post2_self_.get_thread(thread_ptr).state
    == pre_self_.get_thread(thread_ptr).state);
assert(post1_self_.get_thread(thread_ptr).state
    == post2_self_.get_thread(thread_ptr).state);

assert(post1_self_.get_thread(thread_ptr).owning_proc
    == pre_self_.get_thread(thread_ptr).owning_proc);
assert(post2_self_.get_thread(thread_ptr).owning_proc
    == pre_self_.get_thread(thread_ptr).owning_proc);
assert(post1_self_.get_thread(thread_ptr).owning_proc
    == post2_self_.get_thread(thread_ptr).owning_proc);

// --- containers_unchanged_except / containers_unchanged: pointwise --------
// `set![pre_self_.get_endpoint(...).owning_container]` is the same closed
// term in both runs' ensures, so the two `containers_unchanged_except`
// quantifiers share their `changed` set.
let changed_c: ContainerPtr = pre_self_.get_endpoint(
    pre_self_.get_thread(thread_ptr).endpoint_descriptors[edp_idx as int].unwrap()
).owning_container;
let changed_set: Set<ContainerPtr> = set![changed_c];

assert forall|c: ContainerPtr| #![trigger pre_self_.get_container(c)]
    pre_self_.container_dom().contains(c) && c != changed_c implies
        post1_self_.get_container(c) == post2_self_.get_container(c)
by {
    assert(!changed_set.contains(c));
    assert(post1_self_.container_dom().contains(c));
    assert(post2_self_.container_dom().contains(c));
    // r1 case: either containers_unchanged (None) or containers_unchanged_except (Some)
    if r1 is Some {
        assert(post1_self_.get_container(c) =~= pre_self_.get_container(c));
    } else {
        assert(post1_self_.get_container(c) =~= pre_self_.get_container(c));
    }
    if r2 is Some {
        assert(post2_self_.get_container(c) =~= pre_self_.get_container(c));
    } else {
        assert(post2_self_.get_container(c) =~= pre_self_.get_container(c));
    }
}

// --- containers_tree_unchanged / containers_owned_proc_unchanged ----------
// Both runs preserve the tree-shape and owned-procs fields against `pre`,
// so they agree per-container.
assert forall|c: ContainerPtr| #![trigger pre_self_.get_container(c)]
    pre_self_.container_dom().contains(c) implies
        post1_self_.get_container(c).parent =~= post2_self_.get_container(c).parent
        && post1_self_.get_container(c).children =~= post2_self_.get_container(c).children
        && post1_self_.get_container(c).uppertree_seq =~= post2_self_.get_container(c).uppertree_seq
        && post1_self_.get_container(c).subtree_set =~= post2_self_.get_container(c).subtree_set
        && post1_self_.get_container(c).depth == post2_self_.get_container(c).depth
        && post1_self_.get_container(c).root_process == post2_self_.get_container(c).root_process
        && post1_self_.get_container(c).owned_procs =~= post2_self_.get_container(c).owned_procs
by {
    assert(post1_self_.container_dom().contains(c));
    assert(post2_self_.container_dom().contains(c));
}

// --- Lift get_proc equality to process_perms@ Map equality ----------------
// `process_perms@` and `pre_self_.process_perms@` share the same domain and
// the same per-key `.value()`, and `proc_perms_wf` (a wf conjunct) pins the
// `.addr()` and `.is_init()` parts.  PointsTo is structurally determined by
// `(addr, mem_contents)`, so per-key equality + `=~=` on Map closes this.
assert(post1_self_.process_perms@.dom() =~= post2_self_.process_perms@.dom());
assert forall|p: ProcPtr| #![trigger post1_self_.process_perms@[p]]
    post1_self_.process_perms@.dom().contains(p) implies
        post1_self_.process_perms@[p] == post2_self_.process_perms@[p]
by {
    assert(post2_self_.process_perms@.dom().contains(p));
    assert(pre_self_.proc_dom().contains(p));
    assert(post1_self_.process_perms@[p].addr() == p);
    assert(post2_self_.process_perms@[p].addr() == p);
    assert(post1_self_.process_perms@[p].is_init());
    assert(post2_self_.process_perms@[p].is_init());
    assert(post1_self_.get_proc(p) == post2_self_.get_proc(p));
    assert(post1_self_.process_perms@[p].value() == post2_self_.process_perms@[p].value());
}
assert(post1_self_.process_perms@ =~= post2_self_.process_perms@);
